"""
robot_aipet_relay — AI Pet 板端 ROS2 节点（纯话题模式，无文件）

- 订阅 `aipet/ws/relay_delivery` → 定时解析后转发到 `aipet/bt/relay_task`
- 订阅 `aipet/bt/relay_result` → 转发到 `aipet/ws/relay_result`
- 无任何文件 IO（tasks/、inbox、outbox 全部移除）
"""
import rclpy
from rclpy.node import Node
from std_msgs.msg import String
import json
import os
import time
import signal
from datetime import datetime

PID_FILE_RELAY = '/tmp/relay_node.pid'

def _ensure_single_instance():
    try:
        if os.path.exists(PID_FILE_RELAY):
            with open(PID_FILE_RELAY) as f:
                old_pid = int(f.read().strip())
            if old_pid > 0:
                try:
                    os.kill(old_pid, 15)
                    time.sleep(0.3)
                    os.kill(old_pid, 9)
                except (OSError, ProcessLookupError):
                    pass
        with open(PID_FILE_RELAY, 'w') as f:
            f.write(str(os.getpid()))
    except Exception:
        pass


class AIPetRelayNode(Node):
    """AI Pet 传话 ROS2 节点 — 纯话题桥接"""

    def __init__(self):
        super().__init__('aipet_relay_node')
        self.get_logger().info('🚀 AI Pet 传话节点启动（纯话题模式）')

        # 转发到旧话题（兼容）
        self._relay_delivery_pub = self.create_publisher(String, 'aipet/relay_delivery', 10)
        self._command_delivery_pub = self.create_publisher(String, 'aipet/command_delivery', 10)
        self._chat_delivery_pub = self.create_publisher(String, 'aipet/chat_delivery', 10)
        self._config_pub = self.create_publisher(String, 'aipet/config', 10)
        self._relay_voice_pub = self.create_publisher(String, 'aipet/relay_voice', 10)

        # 核心话题：BT 调度
        self._bt_task_pub = self.create_publisher(String, 'aipet/bt/relay_task', 10)
        self._bt_result_pub = self.create_publisher(String, 'aipet/ws/relay_result', 10)
        self._bt_sim_pub = self.create_publisher(String, 'aipet/bt/sim_config', 10)

        # 订阅 WS 来源
        self.create_subscription(String, 'aipet/ws/relay_delivery', self._on_ws_relay_delivery, 10)
        self.create_subscription(String, 'aipet/ws/command_delivery', self._on_ws_command_delivery, 10)
        self.create_subscription(String, 'aipet/ws/chat_delivery', self._on_ws_chat_delivery, 10)
        self.create_subscription(String, 'aipet/ws/config_response', self._on_ws_config_response, 10)
        self.create_subscription(String, 'aipet/ws/voice_trigger', self._on_ws_voice_trigger, 10)

        # 订阅 BT 结果 → 转发到 WS
        self.create_subscription(String, 'aipet/bt/relay_result', self._on_bt_relay_result, 10)

        # 订阅上行数据
        self.create_subscription(String, 'aipet/status_update', self._on_status_update, 10)
        self.create_subscription(String, 'aipet/send_chat', self._on_send_chat, 10)

        self.get_logger().info('✅ 纯话题模式就绪')

    # ─── WS → BT ───

    def _on_ws_relay_delivery(self, msg):
        try:
            data = json.loads(msg.data)
        except Exception:
            return

        # 解析定时
        sched_str = data.get('scheduled_time') or data.get('scheduledTime') or ''
        scheduled_at = None
        if sched_str:
            try:
                scheduled_at = datetime.fromisoformat(sched_str).timestamp()
            except ValueError:
                pass

        relay_id = data.get('relay_id') or data.get('relayId') or ''
        content = data.get('content', '')

        # 发送到 BT 节点（话题方式）
        task_msg = {
            'relay_id': relay_id,
            'content': content,
            'scheduled_at': scheduled_at if scheduled_at is not None else 0.0,
            'payload': data,
        }
        s = String(); s.data = json.dumps(task_msg, ensure_ascii=False)
        self._bt_task_pub.publish(s)
        self.get_logger().info(f'📨 → BT: {relay_id[:40]}')


        # 同时写入文件（供 bt_relay_node 轮询兜底）
        inbox_path = os.path.join(os.path.dirname(__file__) if __file__ else '/home/cat', '..', '..', '..', '..', '..', 'bt_inbox.json')
        inbox_path = os.path.abspath(os.path.expanduser('~/bt_inbox.json'))
        try:
            existing = []
            if os.path.exists(inbox_path):
                with open(inbox_path) as f:
                    existing = json.load(f)
            existing.append(task_msg)
            with open(inbox_path, 'w') as f:
                json.dump(existing, f, ensure_ascii=False, indent=2)
        except Exception:
            pass

    def _on_ws_command_delivery(self, msg):
        try:
            data = json.loads(msg.data)
        except Exception:
            return
        s = String(); s.data = json.dumps(data, ensure_ascii=False)
        self._command_delivery_pub.publish(s)

    def _on_ws_chat_delivery(self, msg):
        try:
            data = json.loads(msg.data)
        except Exception:
            return
        s = String(); s.data = json.dumps(data, ensure_ascii=False)
        self._chat_delivery_pub.publish(s)

    def _on_ws_config_response(self, msg):
        try:
            data = json.loads(msg.data)
        except Exception:
            return
        s = String(); s.data = json.dumps(data, ensure_ascii=False)
        self._config_pub.publish(s)

    def _on_ws_voice_trigger(self, msg):
        if msg.data:
            s = String(); s.data = msg.data
            self._relay_voice_pub.publish(s)

    # ─── BT 结果 → WS ───

    def _on_bt_relay_result(self, msg):
        self.get_logger().info(f'📤 BT结果: {msg.data[:60]}')
        self._bt_result_pub.publish(msg)

    # ─── 上行 ───

    def _on_status_update(self, msg):
        s = String(); s.data = json.dumps({'type': 'status_update', 'status': json.loads(msg.data)})
        self._bt_result_pub.publish(s)

    def _on_send_chat(self, msg):
        try:
            data = json.loads(msg.data)
        except Exception:
            return
        s = String(); s.data = json.dumps({'type': 'chat', 'content': data.get('content', '')})
        self._bt_result_pub.publish(s)


def main(args=None):
    _ensure_single_instance()
    rclpy.init(args=args)
    node = AIPetRelayNode()
    try:
        rclpy.spin(node)
    except KeyboardInterrupt:
        pass
    finally:
        try:
            os.remove(PID_FILE_RELAY)
        except Exception:
            pass
        node.destroy_node()
        rclpy.shutdown()


if __name__ == '__main__':
    main()
